import{describe,expect,it}from"@jest/globals";import{scaleLinear as d3ScaleLinear}from"d3-scale";import{Interval}from"interval-arithmetic-eval";import{syncSamplerInterval}from"./interval.js";const width=200,height=100,xDomain=[-5,5],yDomain=[-5,5],xScale=d3ScaleLinear().domain(xDomain).range([0,width]),yScale=d3ScaleLinear().domain(yDomain).range([height,0]);function toBeCloseToInterval(e,t,a=.001){if(Interval.isInterval(e)&&Interval.isInterval(t))return Math.abs(e.lo-t.lo)>a||Math.abs(e.hi-t.hi)>a?{message:()=>`expected ${this.utils.printReceived(e)} to be within range of `+this.utils.printReceived(t),pass:!1}:{pass:!0};throw new Error("got and want must be Intervals")}expect.extend({toBeCloseToInterval:toBeCloseToInterval}),describe("interval sampler",()=>{describe("with linear sampler",()=>{it("should render 2 points for x",()=>{var e={d:{fn:"1000000*x",fnType:"linear"},range:xDomain,xScale:xScale,yScale:yScale,xAxis:{type:"linear"},yAxis:{type:"linear"},nSamples:2},e=syncSamplerInterval(e);expect(e instanceof Array).toEqual(!0),expect(e.length).toEqual(1),expect(e[0].length).toEqual(1),expect(e[0][0].length).toEqual(2),expect(e[0][0][0]).toBeCloseToInterval({lo:-5,hi:5}),expect(e[0][0][1]).toBeCloseToInterval({lo:-5e6,hi:5e6})}),it("should render 100000 points for x^2",()=>{var e={d:{fn:"x^2",fnType:"linear"},range:xDomain,xScale:xScale,yScale:yScale,xAxis:{type:"linear"},yAxis:{type:"linear"},nSamples:100001},e=syncSamplerInterval(e);expect(e instanceof Array).toEqual(!0),expect(e.length).toEqual(1),expect(e[0].length).toEqual(1e5),expect(e[0][0][0]).toBeCloseToInterval({lo:-5,hi:-5}),expect(e[0][0][1]).toBeCloseToInterval({lo:25,hi:25}),expect(e[0][5e4][0]).toBeCloseToInterval({lo:0,hi:0}),expect(e[0][5e4][1]).toBeCloseToInterval({lo:0,hi:0}),expect(e[0][99999][0]).toBeCloseToInterval({lo:5,hi:5}),expect(e[0][99999][1]).toBeCloseToInterval({lo:25,hi:25})}),it("should render 1 group for 1/x",()=>{var e={d:{fn:"1/x",fnType:"linear"},range:xDomain,xScale:xScale,yScale:yScale,xAxis:{type:"linear"},yAxis:{type:"linear"},nSamples:4},e=syncSamplerInterval(e);expect(e instanceof Array).toEqual(!0),expect(e.length).toEqual(1),expect(e[0].length).toEqual(3),expect(e[0][1]).toEqual(null)})})});